import { Component, OnInit } from "@angular/core";
import { Router } from "@angular/router";
import { ChatService } from "../../services/chat.service";
@Component({
  selector: "app-chat-window",
  templateUrl: "./chat-window.component.html",
  styleUrls: ["./chat-window.component.css"],
})
export class ChatWindowComponent implements OnInit {
  currentUser: any = {
    name: "Ishika",
    email: "ishika@gmail.com",
  };
  searchText = "";
  currentMessage = "";
  selectedUser: any = null;
  messages: any[] = [];
  filteredUsers: any[] = [];
  showMenu = false;
  users: any[] = [
    {
      id: 1,
      name: "Alice Johnson",
      online: true,
      color: "#7b2ff7",
    },
    {
      id: 2,
      name: "Rahul Sharma",
      online: true,
      color: "#9333ea",
    },
    {
      id: 3,
      name: "Sophia Lee",
      online: false,
      color: "#c084fc",
    },
    {
      id: 4,
      name: "David Miller",
      online: true,
      color: "#6d28d9",
    },
    {
      id: 5,
      name: "Emma Watson",
      online: false,
      color: "#8b5cf6",
    },
  ];
  constructor(
    private router: Router,
    private chatService: ChatService,
  ) {}
  ngOnInit(): void {
    const savedUser = localStorage.getItem("currentUser");
    if (savedUser && savedUser !== "undefined") {
      this.currentUser = JSON.parse(savedUser);
    }
    this.filteredUsers = [...this.users];
    if (this.users.length > 0) {
      this.selectUser(this.users[0]);
    }
  }
  selectUser(user: any) {
    this.selectedUser = user;
    this.messages = [];
    this.loadMessages();
  }
  filterUsers() {
    this.filteredUsers = this.users.filter((user: any) =>
      user.name.toLowerCase().includes(this.searchText.toLowerCase()),
    );
  }
  sendMessage() {
    if (!this.currentMessage.trim()) {
      return;
    }
    if (!this.selectedUser) {
      alert("Please Select Chat User");
      return;
    }
    const data = {
      senderEmail: this.currentUser.email,
      senderName: this.currentUser.name,
      receiverName: this.selectedUser.name,
      content: this.currentMessage,
    };
    this.chatService.sendMessage(data).subscribe({
      next: (res: any) => {
        this.messages = [...this.messages, res];
        this.currentMessage = "";
        setTimeout(() => {
          this.autoReply();
        }, 1200);
      },
      error: (err) => {
        console.log(err);
      },
    });
  }
  autoReply() {
    if (!this.selectedUser) {
      return;
    }
    const replies = [
      "Okay 👍",
      "Sounds Great 😊",
      "Awesome 🔥",
      "Interesting 👀",
      "Haha 😂",
      "Lets do it",
      "Sure!",
      "Nice idea 🔥",
      "Cool 😎",
      "I agree 😊",
    ];
    const randomReply = replies[Math.floor(Math.random() * replies.length)];
    const reply = {
      senderName: this.selectedUser.name,
      content: randomReply,
    };
    this.messages = [...this.messages, reply];
  }
  loadMessages() {
    if (!this.selectedUser) {
      return;
    }
    this.chatService
      .getMessages(this.currentUser.name, this.selectedUser.name)
      .subscribe({
        next: (res: any) => {
          this.messages = res;
        },
        error: (err) => {
          console.log(err);
        },
      });
  }
  onFileSelected(event: any) {
    const file = event.target.files[0];
    if (file) {
      const fileMessage = {
        senderName: this.currentUser.name,
        content: "📎 File Sent: " + file.name,
      };
      this.messages = [...this.messages, fileMessage];
    }
  }
  openProfileEditor() {
    this.router.navigate(["/edit-profile"]);
  }
  logout() {
    localStorage.removeItem("currentUser");
    localStorage.removeItem("token");
    this.router.navigate(["/logout"]);
  }
}
<div class="dashboard-container">
<div class="sidebar">
<div class="sidebar-top">
<div class="profile-section">
<div class="profile-avatar">
{{ currentUser?.name?.charAt(0) }}
</div>
<div>
<h3>
{{ currentUser?.name }}
</h3>
<p>TalkIT Messenger</p>
</div>
</div>
<div class="menu-container">
<button class="menu-btn" (click)="showMenu = !showMenu">⋮</button>
<div class="dropdown-menu" *ngIf="showMenu">
<div class="dropdown-item" (click)="openProfileEditor()">
✏ Edit Profile
</div>
<div class="dropdown-item" (click)="logout()">🚪 Logout</div>
</div>
</div>
</div>
<div class="search-box">
<input
type="text"
[(ngModel)]="searchText"
(input)="filterUsers()"
placeholder="Search users..."
/>
</div>
<div class="chat-users">
<div
class="chat-user"
*ngFor="let user of filteredUsers"
(click)="selectUser(user)"
>
<div class="user-avatar" [style.background]="user.color">
{{ user.name.charAt(0) }}
</div>
<div class="user-info">
<h4>
{{ user.name }}
</h4>
<p>
<span
  [class.online-dot]="user.online"
  [class.offline-dot]="!user.online"
></span>
{{ user.online ? "Online" : "Offline" }}
</p>
</div>
</div>
</div>
</div>
<div class="chat-area">
<div *ngIf="!selectedUser" class="empty-chat">
<h1>Start Chatting 💜</h1>
<p>Select a user to start conversation</p>
</div>
<div *ngIf="selectedUser" class="active-chat">
<div class="chat-header">
<div class="chat-user-header">
<div class="user-avatar" [style.background]="selectedUser.color">
{{ selectedUser.name.charAt(0) }}
</div>
<div>
<h3>
  {{ selectedUser.name }}
</h3>
<p>
  {{ selectedUser.online ? "Online" : "Offline" }}
</p>
</div>
</div>
</div>
<div class="chat-messages">
<div
*ngFor="let msg of messages"
class="message-wrapper"
[ngClass]="{
'my-message': msg.senderName === currentUser.name,
'other-message': msg.senderName !== currentUser.name,
}"
>
<div class="message-content">
{{ msg.content }}
</div>
</div>
</div>
<div class="chat-input-section">
<input
type="text"
[(ngModel)]="currentMessage"
placeholder="Type your message..."
(keyup.enter)="sendMessage()"
/>
<input
type="file"
hidden
#fileInput
(change)="onFileSelected($event)"
/>
<button class="attach-btn" (click)="fileInput.click()">📎</button>
<button class="send-btn" (click)="sendMessage()">Send</button>
</div>
</div>
</div>
</div>
